options.customCss:
:root {
  /* تلوين الهوية بالكامل باللون الزيتي المتناسق مع النظام */
  --chat--color--primary: #00767B;
  --chat--color--primary-shade-50: #006266;
  --chat--color--primary--shade-100: #004d50;
  --chat--color--secondary: #00767B;
  --chat--color-secondary-shade-50: #006266;
  --chat--color-white: #fff;
  --chat--color-light: #f5f7fb;
  --chat--color-light-shade-50: #e1e6f0;
  --chat--color-dark: #101330;

  /* ضبط الخلفيات وألوان الرسائل */
  --chat--message--bot--background: var(--chat--color-white);
  --chat--message--bot--color: var(--chat--color-dark);
  --chat--message--user--background: var(--chat--color--primary);
  --chat--message--user--color: var(--chat--color-white);

  /* تعديل لون خلفية الهيدر بالكامل إلى الزيتي المتناسق */
  --chat--header--background: #00767B !important; 
  --chat--input--send--button--color: var(--chat--color--primary);
}

/* تعديل الهيدر لجعل النصوص في المنتصف تماماً */
.chat-header {
  background-color: #00767B !important;
  display: flex !important;
  flex-direction: column !important;
  align-items: center !important; /* توسيط العناصر أفقياً */
  justify-content: center !important;
  text-align: center !important;  /* توسيط النصوص */
  padding: 1.5rem !important;
}

.chat-header h1, .chat-header h2, .chat-header p {
  text-align: center !important;
  width: 100% !important;
  margin: 0.2rem 0 !important;
}

/* حل مشكلة تمدد البوكسات وجعلها تحتضن النص فقط + دعم المحاذاة العربية */
.chat-messages-list {
  direction: rtl !important; 
  display: flex !important;
  flex-direction: column !important;
}

.chat-message {
  width: fit-content !important; 
  max-width: 75% !important;   
  word-break: break-word !important;
  text-align: right !important; 
}

/* دفع رسائل المستخدم لجهة اليمين ورسائل البوت لجهة اليسار بشكل صحيح */
.chat-message.user {
  margin-left: 0 !important;
  margin-right: auto !important;
  align-self: flex-start !important;
}

.chat-message.bot {
  margin-right: 0 !important;
  margin-left: auto !important;
  align-self: flex-end !important;
}

/* ضبط خانة إدخال النص بالأسفل لتكتب من اليمين */
.chat-input textarea {
  direction: rtl !important;
  text-align: right !important;
}
